use note_search_lab::{first_match, Note};

fn notes() -> Vec<Note> {
    vec![
        Note { title: String::from("Rust notes"), body: String::from("Ownership later") },
        Note { title: String::from("Cargo commands"), body: String::from("check run test") },
    ]
}

#[test]
fn finds_first_matching_note() {
    let notes = notes();
    let found = first_match(&notes, "Cargo").expect("expected a match");
    assert_eq!(found.body, "check run test");
}

#[test]
fn returns_none_when_missing() {
    let notes = notes();
    assert!(first_match(&notes, "Tokio").is_none());
}
